import{_ as i,o as t,c as a,ae as o}from"./chunks/framework.Vp2elnCi.js";const u=JSON.parse('{"title":"Why this plugin?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why.md","filePath":"guide/why.md"}'),n={name:"guide/why.md"};function l(s,e,r,c,h,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="why-this-plugin" tabindex="-1">Why this plugin? <a class="header-anchor" href="#why-this-plugin" aria-label="Permalink to &quot;Why this plugin?&quot;">​</a></h1><h2 id="the-real-world-problem" tabindex="-1">The Real-World Problem <a class="header-anchor" href="#the-real-world-problem" aria-label="Permalink to &quot;The Real-World Problem&quot;">​</a></h2><p>In a real project, icon usage often becomes noisy and repetitive:</p><ul><li>Icon files are scattered, naming is inconsistent, and imports are manual.</li><li>Teams fall back to <code>&lt;img src&gt;</code> or ad-hoc inline SVG, which is hard to reuse.</li><li>Color/size control varies by page, and updates are easy to miss.</li><li>Behavior can drift between development, build output, and SSR.</li></ul><p>The issue is not SVG itself.<br> The issue is that icon workflow is rarely treated as a first-class part of the build system.</p><h2 id="why-create-vite-plugin-svg-icons-ng" tabindex="-1">Why create <code>vite-plugin-svg-icons-ng</code> <a class="header-anchor" href="#why-create-vite-plugin-svg-icons-ng" aria-label="Permalink to &quot;Why create `vite-plugin-svg-icons-ng`&quot;">​</a></h2><p><code>vite-plugin-svg-icons-ng</code> was created to make icon usage predictable:</p><ul><li>Take local SVG files as the source of truth.</li><li>Generate sprite output automatically.</li><li>Inject and consume icons in a consistent way.</li><li>Keep the developer loop smooth with cache + HMR.</li></ul><p>The goal is simple: turn icon handling from manual chores into a standard workflow.</p><h2 id="relationship-with-vite-plugin-svg-icons" tabindex="-1">Relationship with <code>vite-plugin-svg-icons</code> <a class="header-anchor" href="#relationship-with-vite-plugin-svg-icons" aria-label="Permalink to &quot;Relationship with `vite-plugin-svg-icons`&quot;">​</a></h2><ul><li>This project is inspired by <a href="https://github.com/vbenjs/vite-plugin-svg-icons" target="_blank" rel="noreferrer"><code>vite-plugin-svg-icons</code></a>, and respects its core sprite-based idea.</li><li><code>vite-plugin-svg-icons-ng</code> provides a fresh feature implementation, code organization, and documentation workflow for this repository.</li></ul><p>If you are migrating from the old plugin, continue with <a href="/vite-plugin-svg-icons-ng/guide/migration.html">Migration from the Old Plugin</a>.</p>',12)])])}const g=i(n,[["render",l]]);export{u as __pageData,g as default};
